const formatTime = t => `${Math.floor(t/60)}:${(t%60).toString().padStart(2,"0")}`;
const confColor  = c => c==="high"?COLORS.agreed:c==="medium"?"#ffd740":"#ff6b6b";
const confLabel  = c => c==="high"?"All 3 models agree":c==="medium"?"2 of 3 agree":"1 model only";

function buildClusters(MODEL_PREDS) {
  const all = Array.from(new Set(Object.values(MODEL_PREDS).flat())).sort((a,b)=>a-b);
  const clusters = [];
  all.forEach(t => {
    const ex = clusters.find(c => Math.abs(c.center - t) <= TOLERANCE * 2);
    if (ex) { ex.members.push(t); ex.center = Math.round(ex.members.reduce((s,v)=>s+v,0)/ex.members.length); }
    else clusters.push({ center: t, members: [t] });
  });
  return clusters.map(c => {
    const contributing = {};
    Object.entries(MODEL_PREDS).forEach(([m,preds]) => {
      if (preds.some(p => Math.abs(p - c.center) <= TOLERANCE * 2)) contributing[m] = true;
    });
    const count = Object.keys(contributing).length;
    return { ...c, contributing, count, confidence: count===3?"high":count===2?"medium":"low" };
  });
}

// ── Ground Truth Chart ───────────────────────────────────────────────────────
function GroundTruthChart({ session }) {
  const { trueBoundaries: TRUE_BOUNDARIES, preds: MODEL_PREDS, dualData: DUAL_DATA, duration: DURATION, label } = session;
  const W=900, H_TOP=220, H_BOT=180, GAP=10;
  const PAD={left:52,right:52,top:18,bottom:28};
  const tMax=DURATION;
  const hrMin=80,hrMax=195,pwrMin=0,pwrMax=400;
  const plotW=W-PAD.left-PAD.right;
  const plotHT=H_TOP-PAD.top-PAD.bottom;
  const txT  = t   => PAD.left+(t/tMax)*plotW;
  const tyH  = hr  => PAD.top+(1-(hr-hrMin)/(hrMax-hrMin))*plotHT;
  const tyP  = pwr => PAD.top+(1-(pwr-pwrMin)/(pwrMax-pwrMin))*plotHT;
  const OFF=H_TOP+GAP;
  const plotHB=H_BOT-PAD.top-PAD.bottom;
  const tyHB = hr => OFF+PAD.top+(1-(hr-hrMin)/(hrMax-hrMin))*plotHB;
  const TOTAL=H_TOP+GAP+H_BOT;

  // smart grid — adapt to session duration
  const step = DURATION <= 2000 ? 300 : DURATION <= 4000 ? 600 : 900;
  const gridTimes = Array.from({length: Math.floor(DURATION/step)+1}, (_,i) => i*step);
  const gridHR=[100,120,140,160,180];
  const gridPwr=[100,200,300,400];

  const hrPathT  = DUAL_DATA.map((d,i)=>`${i===0?"M":"L"}${txT(d.t).toFixed(1)},${tyH(d.hr).toFixed(1)}`).join(" ");
  const pwrPath  = DUAL_DATA.map((d,i)=>`${i===0?"M":"L"}${txT(d.t).toFixed(1)},${tyP(d.pwr).toFixed(1)}`).join(" ");
  const pwrArea  = `M${txT(DUAL_DATA[0].t)},${PAD.top+plotHT} `+DUAL_DATA.map(d=>`L${txT(d.t).toFixed(1)},${tyP(d.pwr).toFixed(1)}`).join(" ")+` L${txT(DUAL_DATA[DUAL_DATA.length-1].t)},${PAD.top+plotHT} Z`;
  const hrPathB  = DUAL_DATA.map((d,i)=>`${i===0?"M":"L"}${txT(d.t).toFixed(1)},${tyHB(d.hr).toFixed(1)}`).join(" ");
  const errColor = e => Math.abs(e)<=TOLERANCE?COLORS.agreed:Math.abs(e)<=30?"#ffd740":"#ff6b6b";

  return (
    <div>
      <div style={{fontSize:10,letterSpacing:"0.1em",color:COLORS.muted,marginBottom:10}}>GROUND TRUTH COMPARISON · {label}</div>
      <div style={{display:"flex",gap:18,marginBottom:10,fontSize:10,color:COLORS.muted,flexWrap:"wrap"}}>
        <span style={{display:"flex",alignItems:"center",gap:5}}><span style={{width:18,height:2,background:COLORS.hr,display:"inline-block",opacity:0.85}}/>HR (bpm)</span>
        <span style={{display:"flex",alignItems:"center",gap:5}}><span style={{width:18,height:2,background:COLORS.power,display:"inline-block",opacity:0.5}}/>Power avg (W)</span>
        <span style={{display:"flex",alignItems:"center",gap:5}}><span style={{width:2,height:12,background:COLORS.truth,display:"inline-block",boxShadow:`0 0 4px ${COLORS.truth}`}}/>Ground truth</span>
        {Object.entries(MODELS).map(([k,m])=>(
          <span key={k} style={{display:"flex",alignItems:"center",gap:5}}>
            <span style={{width:18,height:2,background:m.color,display:"inline-block"}}/><span style={{color:m.color}}>{m.label}</span>
          </span>
        ))}
      </div>
      <div style={{background:COLORS.surface,border:`1px solid ${COLORS.border}`,borderRadius:8,padding:"6px 0 4px"}}>
        <div style={{display:"flex",padding:"0 12px 4px",justifyContent:"space-between"}}>
          <span style={{fontSize:9,color:COLORS.muted,letterSpacing:"0.07em"}}>① REFERENCE — HR + POWER + GROUND TRUTH</span>
        </div>
        <svg width="100%" viewBox={`0 0 ${W} ${TOTAL}`} style={{display:"block"}}>
          <line x1={PAD.left} x2={W-PAD.right} y1={H_TOP+GAP/2} y2={H_TOP+GAP/2} stroke={COLORS.border} strokeWidth={1} strokeDasharray="4,4"/>
          <text x={PAD.left} y={H_TOP+GAP/2-3} fill={COLORS.muted} fontSize={8} opacity={0.6}>② MODEL PREDICTIONS</text>
          {/* TOP grid */}
          {gridHR.map(hr=><line key={hr} x1={PAD.left} x2={W-PAD.right} y1={tyH(hr)} y2={tyH(hr)} stroke={COLORS.border} strokeWidth={0.5}/>)}
          {gridTimes.map(t=><line key={t} x1={txT(t)} x2={txT(t)} y1={PAD.top} y2={H_TOP-PAD.bottom} stroke={COLORS.border} strokeWidth={0.5}/>)}
          {gridHR.map(hr=><text key={hr} x={PAD.left-6} y={tyH(hr)+3} textAnchor="end" fill={COLORS.hr} fontSize={9} opacity={0.65}>{hr}</text>)}
          <text x={12} y={H_TOP/2} textAnchor="middle" fill={COLORS.hr} fontSize={8} opacity={0.5} transform={`rotate(-90,12,${H_TOP/2})`}>bpm</text>
          {gridPwr.map(p=><text key={p} x={W-PAD.right+5} y={tyP(p)+3} textAnchor="start" fill={COLORS.power} fontSize={9} opacity={0.55}>{p}W</text>)}
          <text x={W-10} y={H_TOP/2} textAnchor="middle" fill={COLORS.power} fontSize={8} opacity={0.5} transform={`rotate(90,${W-10},${H_TOP/2})`}>watts</text>
          {TRUE_BOUNDARIES.slice(1).map((t,i)=>(
            <rect key={t} x={txT(TRUE_BOUNDARIES[i])} y={PAD.top} width={txT(t)-txT(TRUE_BOUNDARIES[i])} height={plotHT} fill={i%2===0?"rgba(105,240,174,0.04)":"rgba(79,195,247,0.03)"}/>
          ))}
          <path d={pwrArea} fill={COLORS.power} opacity={0.07}/>
          <path d={pwrPath} fill="none" stroke={COLORS.power} strokeWidth={1.2} opacity={0.4}/>
          <path d={hrPathT} fill="none" stroke={COLORS.hr} strokeWidth={1.8} opacity={0.85}/>
          {TRUE_BOUNDARIES.slice(1).map(t=>(
            <g key={`gt-${t}`}>
              <line x1={txT(t)} x2={txT(t)} y1={PAD.top} y2={H_TOP-PAD.bottom} stroke={COLORS.truth} strokeWidth={2} opacity={0.9}/>
              <circle cx={txT(t)} cy={PAD.top+7} r={3.5} fill={COLORS.truth} opacity={0.9}/>
            </g>
          ))}
          {/* BOTTOM grid */}
          {gridHR.map(hr=><line key={`bg-${hr}`} x1={PAD.left} x2={W-PAD.right} y1={tyHB(hr)} y2={tyHB(hr)} stroke={COLORS.border} strokeWidth={0.5}/>)}
          {gridTimes.map(t=>(
            <g key={`bt-${t}`}>
              <line x1={txT(t)} x2={txT(t)} y1={OFF+PAD.top} y2={OFF+plotHB+PAD.top} stroke={COLORS.border} strokeWidth={0.5}/>
              <text x={txT(t)} y={TOTAL-8} textAnchor="middle" fill={COLORS.muted} fontSize={9}>{formatTime(t)}</text>
            </g>
          ))}
          {gridHR.map(hr=><text key={`bax-${hr}`} x={PAD.left-6} y={tyHB(hr)+3} textAnchor="end" fill={COLORS.hr} fontSize={9} opacity={0.35}>{hr}</text>)}
          <path d={hrPathB} fill="none" stroke={COLORS.hr} strokeWidth={1.2} opacity={0.25}/>
          {TRUE_BOUNDARIES.slice(1).map(t=>(
            <line key={`bgtt-${t}`} x1={txT(t)} x2={txT(t)} y1={OFF+PAD.top} y2={OFF+plotHB+PAD.top} stroke={COLORS.truth} strokeWidth={1.5} strokeDasharray="3,3" opacity={0.4}/>
          ))}
          {Object.entries(MODEL_PREDS).map(([model,preds])=>
            preds.slice(1).map(t=>(
              <line key={`${model}-${t}`} x1={txT(t)} x2={txT(t)} y1={OFF+PAD.top} y2={OFF+plotHB+PAD.top} stroke={MODELS[model].color} strokeWidth={1.8} opacity={0.75}/>
            ))
          )}
          {Object.entries(MODEL_PREDS).map(([model,preds],mi)=>
            preds.slice(1).map(t=>(
              <circle key={`dot-${model}-${t}`} cx={txT(t)} cy={OFF+PAD.top+6+(mi*8)} r={2.5} fill={MODELS[model].color} opacity={0.85}/>
            ))
          )}
        </svg>
      </div>
      {/* Error table */}
      <div style={{marginTop:16}}>
        <div style={{fontSize:10,letterSpacing:"0.1em",color:COLORS.muted,marginBottom:8}}>BOUNDARY ERROR TABLE</div>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}>
            <thead>
              <tr>
                {["#","Ground Truth",...Object.values(MODELS).map(m=>m.label)].map((h,i)=>(
                  <th key={h} style={{textAlign:"left",padding:"5px 12px",borderBottom:`1px solid ${COLORS.border}`,
                    color:i===0?COLORS.muted:i===1?COLORS.truth:Object.values(MODELS)[i-2].color,
                    fontWeight:"normal",letterSpacing:"0.06em",fontSize:10}}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {TRUE_BOUNDARIES.slice(1).map((gt,i)=>(
                <tr key={gt} style={{borderBottom:`1px solid ${COLORS.border}22`}}>
                  <td style={{padding:"5px 12px",color:COLORS.muted,fontSize:10}}>{i+1}</td>
                  <td style={{padding:"5px 12px",color:COLORS.truth,fontWeight:"bold"}}>{formatTime(gt)}</td>
                  {Object.entries(MODEL_PREDS).map(([model,preds])=>{
                    const pred=preds[i+1];
                    const err=pred!==undefined?pred-gt:null;
                    return (
                      <td key={model} style={{padding:"5px 12px",color:err!==null?errColor(err):COLORS.muted}}>
                        {err!==null?<>{formatTime(pred)} <span style={{opacity:0.5,fontSize:10}}>({err>0?"+":""}{err}s)</span></>:"—"}
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div style={{marginTop:6,fontSize:10,color:COLORS.muted}}>
          <span style={{color:COLORS.agreed}}>■</span> within ±{TOLERANCE}s &nbsp;
          <span style={{color:"#ffd740"}}>■</span> within ±30s &nbsp;
          <span style={{color:"#ff6b6b"}}>■</span> outside ±30s
        </div>
      </div>
    </div>
  );
}

// ── Main App ─────────────────────────────────────────────────────────────────
export default function App() {
  const [sessionIdx, setSessionIdx] = useState(10); // default: Luftpresser
  const [tab,        setTab]        = useState("annotate");
  const [showLow,    setShowLow]    = useState(false);
  const [accepted,   setAccepted]   = useState(new Set());
  const [dismissed,  setDismissed]  = useState(new Set());
  const [manual,     setManual]     = useState([]);
  const svgRef = useRef(null);

  const session = ALL_SESSIONS[sessionIdx];
  const { trueBoundaries: TRUE_BOUNDARIES, preds: MODEL_PREDS, dualData: DUAL_DATA,
          duration: DURATION, label, athlete, sport, durationLabel, fbeta } = session;

  const ALL_MARKERS = useMemo(() => buildClusters(MODEL_PREDS), [sessionIdx]);
  const HIGH = useMemo(() => ALL_MARKERS.filter(m=>m.confidence==="high"),  [ALL_MARKERS]);
  const MED  = useMemo(() => ALL_MARKERS.filter(m=>m.confidence==="medium"),[ALL_MARKERS]);
  const LOW  = useMemo(() => ALL_MARKERS.filter(m=>m.confidence==="low"),   [ALL_MARKERS]);

  // Reset annotation state when session changes
  useEffect(() => {
    setAccepted(new Set(HIGH.map(m=>m.center)));
    setDismissed(new Set());
    setManual([]);
    setShowLow(false);
  }, [sessionIdx]);

  const W=900, H=240, PAD={left:44,right:16,top:18,bottom:32};
  const plotW=W-PAD.left-PAD.right;
  const plotH=H-PAD.top-PAD.bottom;
  const hrMin=80, hrMax=195;

  const tx = t  => PAD.left + (t/DURATION)*plotW;
  const ty = hr => PAD.top  + (1-(hr-hrMin)/(hrMax-hrMin))*plotH;
  const hrPath = DUAL_DATA.map((d,i)=>`${i===0?"M":"L"}${tx(d.t).toFixed(1)},${ty(d.hr).toFixed(1)}`).join(" ");

  const accept  = c => { setAccepted(p=>new Set([...p,c])); setDismissed(p=>{const n=new Set(p);n.delete(c);return n;}); };
  const dismiss = c => { setDismissed(p=>new Set([...p,c])); setAccepted(p=>{const n=new Set(p);n.delete(c);return n;}); };

  const handleClick = e => {
    if (tab!=="annotate") return;
    const rect = svgRef.current.getBoundingClientRect();
    const x = (e.clientX-rect.left)*(W/rect.width);
    const t = Math.round(((x-PAD.left)/plotW)*DURATION);
    if (t>10 && t<DURATION-10) setManual(p=>[...p,t]);
  };

  const visible  = [...HIGH,...MED,...(showLow?LOW:[])].filter(m=>!dismissed.has(m.center));
  const progress = Math.min(100, Math.round((accepted.size/(TRUE_BOUNDARIES.length-1))*100));
  const step = DURATION <= 2000 ? 300 : DURATION <= 4000 ? 600 : 900;
  const gridTimes = Array.from({length: Math.floor(DURATION/step)+1}, (_,i) => i*step);
  const gridHR = [100,120,140,160,180];

  const athleteDisplay = athlete.replace("AthletesSpecial","").replace("Athlete","ATH_") || athlete;

  return (
    <div style={{background:COLORS.bg,minHeight:"100vh",fontFamily:"'DM Mono','Courier New',monospace",color:COLORS.text}}>
      {/* Header */}
      <div style={{borderBottom:`1px solid ${COLORS.border}`,padding:"13px 24px",display:"flex",alignItems:"center",justifyContent:"space-between",background:COLORS.surface,flexWrap:"wrap",gap:10}}>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <div style={{width:7,height:7,borderRadius:"50%",background:COLORS.agreed,boxShadow:`0 0 7px ${COLORS.agreed}`}}/>
          <span style={{fontSize:11,letterSpacing:"0.12em",color:COLORS.muted}}>INTERVAL ANNOTATION</span>
          <span style={{background:"#1e3a2e",color:COLORS.agreed,fontSize:10,padding:"2px 8px",borderRadius:3,letterSpacing:"0.04em"}}>{sport} · {label}</span>
        </div>
        {/* Session picker */}
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <span style={{fontSize:10,color:COLORS.muted,letterSpacing:"0.08em"}}>SESSION</span>
          <select
            value={sessionIdx}
            onChange={e=>setSessionIdx(Number(e.target.value))}
            style={{background:COLORS.surface,color:COLORS.text,border:`1px solid ${COLORS.border}`,borderRadius:4,padding:"4px 8px",fontSize:11,fontFamily:"inherit",cursor:"pointer",outline:"none"}}
          >
            {ALL_SESSIONS.map((s,i)=>(
              <option key={s.id} value={i}>[{s.sport}] {s.label}</option>
            ))}
          </select>
        </div>
        <div style={{display:"flex",gap:22,fontSize:11,color:COLORS.muted}}>
          <span>Duration: <b style={{color:COLORS.text}}>{durationLabel}</b></span>
          <span>Athlete: <b style={{color:COLORS.text}}>{athleteDisplay}</b></span>
          <span>True boundaries: <b style={{color:COLORS.text}}>{TRUE_BOUNDARIES.length-1}</b></span>
        </div>
      </div>

      {/* Tabs */}
      <div style={{display:"flex",borderBottom:`1px solid ${COLORS.border}`,padding:"0 24px",background:COLORS.surface}}>
        {["annotate","ground truth","models","summary"].map(t=>(
          <button key={t} onClick={()=>setTab(t)} style={{background:"none",border:"none",borderBottom:tab===t?`2px solid ${COLORS.bilstm}`:"2px solid transparent",color:tab===t?COLORS.text:COLORS.muted,padding:"9px 18px",fontSize:11,letterSpacing:"0.08em",textTransform:"uppercase",cursor:"pointer",marginBottom:-1}}>{t}</button>
        ))}
      </div>

      <div style={{padding:"20px 24px"}}>

        {/* ── ANNOTATE TAB ── */}
        {tab==="annotate" && (<>
          <div style={{marginBottom:16}}>
            <div style={{display:"flex",justifyContent:"space-between",marginBottom:5,fontSize:10,color:COLORS.muted,letterSpacing:"0.08em"}}>
              <span>ANNOTATION PROGRESS</span>
              <span style={{color:accepted.size>=(TRUE_BOUNDARIES.length-1)?COLORS.agreed:COLORS.text}}>{accepted.size} / {TRUE_BOUNDARIES.length-1} confirmed</span>
            </div>
            <div style={{background:COLORS.border,borderRadius:2,height:3}}>
              <div style={{width:`${progress}%`,height:"100%",borderRadius:2,background:`linear-gradient(90deg,${COLORS.bilstm},${COLORS.agreed})`,transition:"width 0.4s ease"}}/>
            </div>
          </div>

          <div style={{display:"flex",gap:18,marginBottom:12,fontSize:10,color:COLORS.muted,flexWrap:"wrap",letterSpacing:"0.03em"}}>
            {[{c:COLORS.agreed,l:"Auto-accepted (3/3)",g:true},{c:"#ffd740",l:"Review needed (2/3)"},{c:"#ff6b6b",l:"Low confidence (1/3)"},{c:COLORS.manual,l:"User-added",d:true}].map(({c,l,g,d})=>(
              <span key={l} style={{display:"flex",alignItems:"center",gap:5}}>
                <span style={{width:8,height:8,borderRadius:"50%",background:c,display:"inline-block",boxShadow:g?`0 0 5px ${c}`:"none",border:d?`1.5px dashed ${c}`:"none"}}/>{l}
              </span>
            ))}
          </div>

          <div style={{background:COLORS.surface,border:`1px solid ${COLORS.border}`,borderRadius:8,padding:"6px 0 0",marginBottom:16,cursor:"crosshair"}}>
            <div style={{fontSize:9,color:COLORS.muted,padding:"0 12px 3px",letterSpacing:"0.07em"}}>HEART RATE (bpm) · Click to add manual boundary</div>
            <svg ref={svgRef} width="100%" viewBox={`0 0 ${W} ${H}`} onClick={handleClick} style={{display:"block"}}>
              {gridHR.map(hr=>(
                <g key={hr}>
                  <line x1={PAD.left} x2={W-PAD.right} y1={ty(hr)} y2={ty(hr)} stroke={COLORS.border} strokeWidth={0.5}/>
                  <text x={PAD.left-5} y={ty(hr)+3} textAnchor="end" fill={COLORS.muted} fontSize={9}>{hr}</text>
                </g>
              ))}
              {gridTimes.map(t=>(
                <g key={t}>
                  <line x1={tx(t)} x2={tx(t)} y1={PAD.top} y2={H-PAD.bottom} stroke={COLORS.border} strokeWidth={0.5}/>
                  <text x={tx(t)} y={H-8} textAnchor="middle" fill={COLORS.muted} fontSize={9}>{formatTime(t)}</text>
                </g>
              ))}
              {(()=>{const s=[...accepted].sort((a,b)=>a-b);return s.map((t,i)=>{const nx=s[i+1];if(!nx)return null;return <rect key={t} x={tx(t)} y={PAD.top} width={tx(nx)-tx(t)} height={plotH} fill={i%2===0?"rgba(79,195,247,0.04)":"rgba(105,240,174,0.03)"}/>;});})()}
              <path d={hrPath} fill="none" stroke={COLORS.hr} strokeWidth={1.5} opacity={0.8}/>
              {visible.filter(m=>!accepted.has(m.center)).map(marker=>(
                <g key={`s-${marker.center}`}>
                  <line x1={tx(marker.center)} x2={tx(marker.center)} y1={PAD.top} y2={H-PAD.bottom} stroke={confColor(marker.confidence)} strokeWidth={1.5} strokeDasharray="4,3" opacity={marker.confidence==="medium"?0.55:0.25}/>
                  {Object.keys(marker.contributing).map((m,mi)=>(<circle key={m} cx={tx(marker.center)+(mi-1)*7} cy={PAD.top+10} r={3} fill={MODELS[m].color} opacity={0.8}/>))}
                </g>
              ))}
              {[...accepted].map(t=>(
                <g key={`a-${t}`}>
                  <line x1={tx(t)} x2={tx(t)} y1={PAD.top} y2={H-PAD.bottom} stroke={COLORS.agreed} strokeWidth={2} opacity={0.9}/>
                  <circle cx={tx(t)} cy={PAD.top+8} r={5} fill={COLORS.agreed} opacity={0.9}/>
                  <text x={tx(t)+5} y={PAD.top+20} fill={COLORS.agreed} fontSize={8} opacity={0.6}>{formatTime(t)}</text>
                </g>
              ))}
              {manual.map((t,i)=>(
                <g key={`m-${i}`}>
                  <line x1={tx(t)} x2={tx(t)} y1={PAD.top} y2={H-PAD.bottom} stroke={COLORS.manual} strokeWidth={1.5} strokeDasharray="6,2"/>
                  <polygon points={`${tx(t)},${PAD.top} ${tx(t)-5},${PAD.top+9} ${tx(t)+5},${PAD.top+9}`} fill={COLORS.manual}/>
                </g>
              ))}
            </svg>
          </div>

          <div style={{marginBottom:14}}>
            <div style={{fontSize:10,letterSpacing:"0.1em",color:COLORS.muted,marginBottom:8}}>REVIEW SUGGESTIONS</div>
            <div style={{display:"flex",flexDirection:"column",gap:5}}>
              {[...HIGH,...MED].filter(m=>!dismissed.has(m.center)).map(marker=>(
                <div key={marker.center} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 12px",background:COLORS.surface,border:`1px solid ${accepted.has(marker.center)?confColor(marker.confidence)+"50":COLORS.border}`,borderRadius:5}}>
                  <div style={{width:7,height:7,borderRadius:"50%",background:confColor(marker.confidence),flexShrink:0,boxShadow:accepted.has(marker.center)?`0 0 5px ${confColor(marker.confidence)}`:"none"}}/>
                  <span style={{color:COLORS.text,minWidth:44,fontSize:12}}>{formatTime(marker.center)}</span>
                  <span style={{color:COLORS.muted,flex:1,fontSize:10}}>{confLabel(marker.confidence)} · {Object.keys(marker.contributing).map(m=><span key={m} style={{color:MODELS[m].color}}>{MODELS[m].label} </span>)}</span>
                  {accepted.has(marker.center)
                    ? <span style={{color:COLORS.agreed,fontSize:10}}>✓ accepted</span>
                    : <div style={{display:"flex",gap:5}}>
                        <button onClick={()=>accept(marker.center)} style={{background:"#1e3a2e",color:COLORS.agreed,border:`1px solid ${COLORS.agreed}40`,borderRadius:4,padding:"3px 10px",fontSize:10,cursor:"pointer"}}>Accept</button>
                        <button onClick={()=>dismiss(marker.center)} style={{background:"transparent",color:COLORS.muted,border:`1px solid ${COLORS.border}`,borderRadius:4,padding:"3px 10px",fontSize:10,cursor:"pointer"}}>Dismiss</button>
                      </div>}
                </div>
              ))}
            </div>
            {LOW.length>0 && <button onClick={()=>setShowLow(!showLow)} style={{marginTop:7,background:"transparent",border:`1px solid ${COLORS.border}`,color:COLORS.muted,fontSize:10,padding:"4px 12px",borderRadius:4,cursor:"pointer"}}>{showLow?"Hide low-confidence":`+ Show ${LOW.length} low-confidence suggestion${LOW.length>1?"s":""}`}</button>}
          </div>

          <div style={{display:"flex",gap:7,flexWrap:"wrap"}}>
            {[
              {l:"Accept all high-confidence",c:COLORS.agreed,bg:"#1e3a2e",a:()=>setAccepted(new Set(HIGH.map(m=>m.center)))},
              {l:"Accept all suggestions",c:COLORS.manual,bg:"#2a2d1e",a:()=>setAccepted(new Set([...HIGH,...MED].map(m=>m.center)))},
              {l:"Reset",c:COLORS.muted,bg:"transparent",a:()=>{setAccepted(new Set());setDismissed(new Set());setManual([]);}},
            ].map(({l,c,bg,a})=>(
              <button key={l} onClick={a} style={{background:bg,color:c,border:`1px solid ${c}30`,borderRadius:4,padding:"5px 12px",fontSize:10,cursor:"pointer"}}>{l}</button>
            ))}
          </div>
        </>)}

        {/* ── GROUND TRUTH TAB ── */}
        {tab==="ground truth" && <GroundTruthChart session={session} />}

        {/* ── MODELS TAB ── */}
        {tab==="models" && (
          <div style={{maxWidth:540}}>
            <div style={{fontSize:10,letterSpacing:"0.1em",color:COLORS.muted,marginBottom:14}}>MODEL OVERVIEW · {label}</div>
            {Object.entries(MODELS).map(([key,m])=>(
              <div key={key} style={{display:"flex",alignItems:"flex-start",gap:12,padding:"13px 14px",background:COLORS.surface,border:`1px solid ${COLORS.border}`,borderRadius:6,marginBottom:8}}>
                <div style={{width:9,height:9,borderRadius:"50%",background:m.color,marginTop:3,boxShadow:`0 0 7px ${m.color}80`,flexShrink:0}}/>
                <div>
                  <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:4}}>
                    <span style={{fontSize:12,color:m.color}}>{m.label}</span>
                    <span style={{fontSize:10,color:COLORS.muted}}>F_β = <b style={{color:m.color}}>{fbeta[key]}</b></span>
                  </div>
                  <div style={{fontSize:11,color:COLORS.muted,lineHeight:1.65}}>
                    {key==="bilstm"&&"Bidirectional LSTM — best overall performer (F_β ≈ 0.722 avg). Captures temporal context in both directions."}
                    {key==="xgboost"&&"Gradient boosted trees — strong on structured rowing data. Session-normalized features with multi-scale rolling windows."}
                    {key==="ffnn"&&"Feedforward network — evolved from VAE architecture via Optuna (50 trials). KL weight collapsed to near-zero → standard feedforward."}
                  </div>
                </div>
              </div>
            ))}
            <div style={{marginTop:14,padding:"12px 14px",background:"#1a2030",border:`1px solid ${COLORS.bilstm}25`,borderRadius:6,fontSize:11,color:COLORS.muted,lineHeight:1.7}}>
              <span style={{color:COLORS.bilstm}}>Agreement strategy: </span>
              Predictions are grouped by temporal clustering (±10 s window). Confidence reflects model consensus. 3/3 → auto-accepted; 2/3 → flagged for review; 1/3 → hidden by default.
            </div>
          </div>
        )}

        {/* ── SUMMARY TAB ── */}
        {tab==="summary" && (
          <div style={{maxWidth:540}}>
            <div style={{fontSize:10,letterSpacing:"0.1em",color:COLORS.muted,marginBottom:14}}>SESSION SUMMARY · {label}</div>
            {[
              ["Session ID", session.id],
              ["Sport", sport],
              ["Athlete", athlete],
              ["Duration", durationLabel],
              ["True boundaries", TRUE_BOUNDARIES.length-1],
              ["High-conf clusters (3/3 agree)", HIGH.length],
              ["Medium-conf clusters (2/3 agree)", MED.length],
              ["Low-conf clusters (1/3 agree)", LOW.length],
              ["Auto-accepted", HIGH.length],
              ["User-confirmed", accepted.size],
              ["User-added (manual)", manual.length],
              ["Dismissed", dismissed.size],
              ["BiLSTM F_β", fbeta.bilstm],
              ["XGBoost F_β", fbeta.xgboost],
              ["FFNN F_β", fbeta.ffnn],
            ].map(([lbl,val])=>(
              <div key={lbl} style={{display:"flex",justifyContent:"space-between",padding:"7px 14px",borderBottom:`1px solid ${COLORS.border}`,fontSize:12}}>
                <span style={{color:COLORS.muted}}>{lbl}</span>
                <span style={{color:COLORS.text,fontWeight:"bold"}}>{val}</span>
              </div>
            ))}
            <div style={{marginTop:18,padding:"12px 14px",background:"#1a2030",border:`1px solid ${COLORS.agreed}30`,borderRadius:6,fontSize:11,color:COLORS.muted,lineHeight:1.7}}>
              <span style={{color:COLORS.agreed}}>Efficiency: </span>
              {HIGH.length}/{TRUE_BOUNDARIES.length-1} boundaries ({Math.round(HIGH.length/(TRUE_BOUNDARIES.length-1)*100)}%) auto-accepted. Only {MED.length} required user review.
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
